};

return (
<div style={{ padding: 20 }}> <h1>Memora AI</h1>

```
  <div style={{ height: "60vh", overflow: "auto", border: "1px solid gray", padding: 10 }}>
    {messages.map((m, i) => (
      <div key={i}>
        <b>{m.role}:</b> {m.message}
      </div>
    ))}
  </div>

  <input
    value={input}
    onChange={(e) => setInput(e.target.value)}
    onKeyDown={(e) => e.key === "Enter" && sendMessage()}
    placeholder="Ask something..."
    style={{ width: "70%", padding: 10 }}
  />

  <button onClick={sendMessage} style={{ padding: 10 }}>
    Send
  </button>
</div>


);
}

export default App;
